insert into bank_questions (question_key, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('4-4-consumer-law:mcq:f04710e6', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "Consumer law requires shops to sell goods which are:", "options": ["Environmentally friendly", "Of satisfactory quality", "Reasonably priced", "Unique"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Of satisfactory quality. The Consumer Rights Act 2015 specifically requires goods to be of satisfactory quality — not defective or damaged when sold. Environmental responsibility, pricing, and uniqueness are not legal requirements under consumer law."}'::jsonb),
('4-4-consumer-law:mcq:dfdbce5c', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "Within how many days can a customer return faulty goods for a full refund under the Consumer Rights Act 2015?", "options": ["14 days", "21 days", "30 days", "60 days"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — 30 days. The Consumer Rights Act 2015 gives customers a 30-day window to return faulty goods for a full refund. After 30 days, the right to an automatic full refund ends — within 6 months, a repair or replacement is offered first."}'::jsonb),
('4-4-consumer-law:mcq:c993e623', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "If a product develops a fault within the first six months of purchase, who must prove the fault was pre-existing?", "options": ["The customer", "The manufacturer", "The seller", "An independent tribunal"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — The seller. Within the first 6 months, it is assumed the fault was present at the time of purchase. The seller must prove otherwise. After 6 months, the burden of proof shifts to the customer."}'::jsonb),
('4-4-consumer-law:mcq:2c56f9d0', '4-4-consumer-law', '4.4 Consumer Law', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a requirement of the Consumer Rights Act 2015?", "options": ["Of satisfactory quality", "Fit for purpose", "As described", "Cheapest price on the market"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — Cheapest price on the market. The three requirements under the Consumer Rights Act 2015 are: satisfactory quality, fit for purpose, and as described. There is no requirement for businesses to sell at the lowest market price."}'::jsonb),
('4-4-consumer-law:tf:f24e6c65', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "The Consumer Rights Act says that goods must always be of the best possible quality."}'::jsonb, '{"answer": false, "explain": "FALSE. The Consumer Rights Act only requires goods to be of ''satisfactory quality'' — a standard that reflects the price paid. Cheaper goods have a lower quality expectation than luxury goods; they do not all need to be the best possible standard."}'::jsonb),
('4-4-consumer-law:tf:da697871', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Customers can return faulty goods for a full refund within 30 days of purchase."}'::jsonb, '{"answer": true, "explain": "TRUE. The Consumer Rights Act 2015 gives customers a 30-day window to return faulty goods for a full refund. Businesses must comply with this legal right."}'::jsonb),
('4-4-consumer-law:tf:ef115baa', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "All goods must be described correctly only when they are over £100."}'::jsonb, '{"answer": false, "explain": "FALSE. The ''as described'' requirement applies to ALL goods regardless of their price. Whether a product costs £1 or £1,000, it must match its description exactly."}'::jsonb),
('4-4-consumer-law:tf:49f18b9f', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Safety in goods bought by customers is covered by the Consumer Protection Act 1987."}'::jsonb, '{"answer": true, "explain": "TRUE. The Consumer Protection Act 1987 gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury — specifically covering product safety."}'::jsonb),
('4-4-consumer-law:tf:44b66e9d', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Digital goods such as downloaded music are covered in exactly the same way as physical goods by the Consumer Rights Act."}'::jsonb, '{"answer": false, "explain": "FALSE. Digital products such as downloaded music and apps are NOT covered by the 30-day return rule. Instead, customers can request a replacement or, if not provided, a price reduction of up to 100%."}'::jsonb),
('4-4-consumer-law:tf:9e9bf9f6', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Good training of employees will help a business produce goods of satisfactory quality."}'::jsonb, '{"answer": true, "explain": "TRUE. Investing in employee training helps businesses produce goods that meet the satisfactory quality standard required by consumer law. This directly links to Unit 3.6 (Training)."}'::jsonb),
('4-4-consumer-law:tf:368ca0fb', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "After 30 days, a customer cannot make any claim whatsoever for faulty goods against a business."}'::jsonb, '{"answer": false, "explain": "FALSE. After 30 days, the right to a full refund ends, but customers retain rights. Within 6 months, they can request a repair or replacement. After 6 months, they can still claim for up to six years if they prove the fault was present at the time of purchase."}'::jsonb),
('4-4-consumer-law:tf:8a94e33a', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "A business can face compensation claims if its products cause personal injury or death."}'::jsonb, '{"answer": true, "explain": "TRUE. Under the Consumer Protection Act 1987, customers can claim compensation for death, damage, or personal injury caused by defective products. This can result in huge financial costs for the business."}'::jsonb),
('4-4-consumer-law:tf:a3975e62', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Consumer law only applies to physical products and does not cover services such as plumbing or hairdressing."}'::jsonb, '{"answer": false, "explain": "FALSE. The Consumer Rights Act 2015 also covers services. If a service is not completed in the agreed time or to a reasonable standard, customers can request the work to be redone or receive a price reduction of up to 100%."}'::jsonb),
('4-4-consumer-law:tf:9aae27fc', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "If a fault develops after six months, it is the seller''s responsibility to prove the fault was not there at the time of purchase."}'::jsonb, '{"answer": false, "explain": "FALSE. After six months, the burden of proof shifts to the customer — they must prove the fault existed at the time of delivery. Within the first six months, it is the seller who must prove otherwise."}'::jsonb),
('4-4-consumer-law:tf:12b98971', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "A business that complies with consumer law may benefit from an improved reputation."}'::jsonb, '{"answer": true, "explain": "TRUE. Consistently selling goods that are of satisfactory quality, fit for purpose, and as described helps build a strong reputation, increasing customer loyalty and sales over time."}'::jsonb),
('4-4-consumer-law:tf:afb84288', '4-4-consumer-law', '4.4 Consumer Law', 'tf', 'tf', 1, '{"question": "Social media makes it easier for businesses to conceal poor quality products from consumers."}'::jsonb, '{"answer": false, "explain": "FALSE. Social media makes it significantly harder for businesses to conceal product issues. Customers can post negative reviews publicly and these can spread rapidly, causing serious reputational damage far beyond the original complaint."}'::jsonb),
('4-4-consumer-law:learn:f912d89b', '4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>Consumer law protects customers when they buy goods and services. The main piece of legislation you need to understand is the <strong>Consumer Rights Act 2015</strong>.</p>\n    <ul>\n      <li><strong>Consumer Law:</strong> The area of law that protects the customers of a business. This is mainly through the Consumer Rights Act 2015.</li>\n      <li><strong>Consumer Rights Act 2015:</strong> An act of parliament that gives customers protection when they buy goods and services — they must be of satisfactory quality, fit for purpose, and as described.</li>\n      <li><strong>Satisfactory Quality:</strong> How the goods are made must reflect the price. A high-priced product must be of high quality. Goods must not be damaged or faulty when bought.</li>\n      <li><strong>Fit for Purpose:</strong> Goods must do what they are meant to do. If the seller claims that a product performs a particular function, it must be able to do that.</li>\n      <li><strong>As Described:</strong> Goods must be exactly as described or advertised. If you ordered an orange-coloured bike, you should receive an orange bike — not a green one.</li>\n      <li><strong>Reputation:</strong> What customers say and feel about a business. Damage to a reputation can seriously affect a business''s long-term survival and sales.</li>\n      <li><strong>Compensation:</strong> A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987.</li>\n      <li><strong>Consumer Protection Act 1987:</strong> Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.</li>\n    </ul>", "question": "Under which act can consumers claim compensation if a defective product causes death, damage, or personal injury?", "options": ["Consumer Protection Act 1987", "Consumer Rights Act 2015", "Sale of Goods Act 1979", "Trade Descriptions Act 1968"]}'::jsonb, '{"answer": 0, "explain": "The Consumer Protection Act 1987 specifically gives consumers the right to claim compensation for defective products causing death, damage, or personal injury."}'::jsonb),
('4-4-consumer-law:learn:3acd86e6', '4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "The Consumer Rights Act 2015: The Three Requirements", "reading": "<p>The <strong>Consumer Rights Act 2015</strong> is the key law protecting customers in the UK. It states that all goods and services sold to customers must meet three requirements. Businesses that fail to comply face serious legal and financial consequences.</p>\n    <ul>\n      <li><strong>1. Of Satisfactory Quality:</strong> Goods must not be damaged or faulty when bought. The quality expected should reflect the price paid — cheaper ''bargains'' are expected to have lower quality than luxury goods. All goods must be appropriate for their price point.</li>\n      <li><strong>2. Fit for Purpose:</strong> Goods must do what they are meant to do. If the seller claims a product performs a specific function, it must be able to do it. For example, a waterproof jacket must actually be waterproof.</li>\n      <li><strong>3. As Described:</strong> Goods must match their description exactly. If you order orange trainers online, you should receive orange ones — not blue ones.</li>\n    </ul>\n    <div class=\"case-study-box\">\n      <h4>Applying the Three Requirements — Real Scenarios</h4>\n      <p><strong>Lisa</strong> buys a washing machine and the start button doesn''t work &rarr; <em>Not of satisfactory quality</em> (faulty when bought).</p>\n      <p><strong>Mandy</strong> buys face cream claiming to eliminate wrinkles, but it doesn''t work &rarr; <em>Not fit for purpose</em> (does not do what it claims).</p>\n      <p><strong>Tim</strong> orders a blue top online but receives a green one &rarr; <em>Not as described</em> (product does not match its description).</p>\n      <p><strong>Oliver</strong> buys a jumper in the sale and finds the seam is ripped when he gets home &rarr; Could be <em>not of satisfactory quality</em> — even sale goods must meet basic standards unless the fault was pointed out at the time of purchase.</p>\n    </div>", "question": "Mandy buys face cream claiming to eliminate wrinkles, but it doesn''t work. Which requirement has been breached?", "options": ["Fit for purpose", "Satisfactory quality", "As described", "Consumer Protection Act 1987"]}'::jsonb, '{"answer": 0, "explain": "The cream fails to do what the seller claimed it would do, so it is not fit for purpose."}'::jsonb),
('4-4-consumer-law:learn:8b727b30', '4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "Time-Based Customer Rights Under the Consumer Rights Act", "reading": "<p>The Consumer Rights Act also gives customers specific rights depending on <strong>when</strong> a fault is discovered after purchase. These rights change at key time thresholds.</p>\n    <ul>\n      <li><strong>Within 30 Days — Full Refund:</strong> A customer can return faulty goods for a full refund. Important exception: this does <strong>NOT</strong> apply to digital products such as downloaded music or apps. For digital goods, a customer can request a replacement or, if not provided, a price reduction of up to 100%.</li>\n      <li><strong>Within the First 6 Months — Seller''s Burden of Proof:</strong> If a product develops a fault within the first six months, it is assumed the fault was present at the time of purchase. The <strong>seller</strong> must prove otherwise. The customer may request a repair, replacement, or price reduction.</li>\n      <li><strong>After 6 Months — Customer''s Burden of Proof:</strong> It is up to the <strong>customer</strong> to prove that the fault was present at the time of delivery. This is significantly more difficult. Customers have up to <strong>six years</strong> to complete a claim against the seller.</li>\n      <li><strong>Services:</strong> If a service (e.g. a kitchen fitter or plumber) is not completed in the agreed time or to a reasonable standard, the customer can request the work to be redone. If that is not possible, a price reduction of up to 100% should be agreed.</li>\n    </ul>", "question": "Within how many months of purchase does the burden of proof fall on the seller, not the customer, to show a fault wasn''t present at purchase?", "options": ["6 months", "30 days", "12 months", "6 years"]}'::jsonb, '{"answer": 0, "explain": "Within the first 6 months, a fault is assumed to have been present at purchase and the seller must prove otherwise."}'::jsonb),
('4-4-consumer-law:learn:e5ee9b3f', '4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "The Impact of Consumer Law on Business", "reading": "<p>Consumer law has several significant impacts on how a business must operate. Businesses need to plan carefully to comply — and face serious consequences if they do not.</p>\n    <ul>\n      <li><strong>Production of Quality Goods:</strong> Businesses must ensure goods are produced to a standard that meets legal requirements. This affects how businesses train employees (links to Unit 3.6) and what quality control procedures they use (links to Unit 4.2). If goods are returned for refunds, costs increase and profits fall.</li>\n      <li><strong>Safety of Goods:</strong> Under the Consumer Protection Act 1987, if defective products cause death, injury, or damage to property, customers can claim compensation. This can result in huge financial costs and forces firms to maintain strict safety procedures throughout production.</li>\n      <li><strong>Loss of Reputation:</strong> If a business produces poor-quality or defective goods, customers will complain — often publicly on social media. Negative reviews spread rapidly, damaging a business''s reputation and driving customers to competitors. In extreme cases, this could lead to the business closing down entirely.</li>\n      <li><strong>Training Costs:</strong> To comply with consumer law, businesses must invest in training employees to produce goods of the required quality standard. This increases operating costs but reduces the risk of producing defective goods that lead to costly refunds or legal claims.</li>\n    </ul>", "question": "According to this topic, what is the main risk when customers complain about poor-quality goods online?", "options": ["Negative reviews spread fast and damage its reputation", "An automatic fine gets issued by Trading Standards", "Staff training costs are cut to zero at once", "Customers permanently lose their refund rights"]}'::jsonb, '{"answer": 0, "explain": "The card explains that negative reviews spread rapidly on social media, damaging reputation and pushing customers towards competitors."}'::jsonb),
('4-4-consumer-law:learn:fdffe293', '4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of Complying with Consumer Law", "reading": "<p>For a 7-mark ''evaluate'' or ''discuss'' question, you must be able to argue both sides. Complying with consumer law creates both benefits and challenges for a business.</p>\n    <div class=\"two-col\">\n      <div>\n        <div class=\"col-head\">✓ Advantages of Complying</div>\n        <div class=\"pro-item\"><strong>Improved Reputation:</strong> Consistently selling high-quality, correctly described goods builds a strong reputation, increasing customer loyalty and long-term sales revenue.</div>\n        <div class=\"pro-item\"><strong>Fewer Returns & Refunds:</strong> Producing goods of satisfactory quality reduces costly refund and return processing, directly protecting profit margins.</div>\n        <div class=\"pro-item\"><strong>Avoids Legal Action:</strong> Compliance prevents costly compensation claims and court proceedings, protecting the business financially and reputationally.</div>\n        <div class=\"pro-item\"><strong>Competitive Advantage:</strong> A business known for quality and reliability can differentiate itself from competitors and attract more customers over time.</div>\n      </div>\n      <div>\n        <div class=\"col-head\">✗ Disadvantages of Complying</div>\n        <div class=\"con-item\"><strong>Training Costs:</strong> Investing in employee training to ensure goods meet quality standards adds to operating costs, reducing short-term profits.</div>\n        <div class=\"con-item\"><strong>Higher Production Costs:</strong> Meeting quality standards may require better raw materials or upgraded equipment, raising the cost of production.</div>\n        <div class=\"con-item\"><strong>Refund & Compensation Risk:</strong> Even compliant businesses may face unexpected refund demands or compensation claims if products fail, creating unpredictable costs.</div>\n        <div class=\"con-item\"><strong>Reputational Risk Remains:</strong> Even one high-profile product failure — especially amplified on social media — can cause lasting damage despite a strong compliance record.</div>\n      </div>\n    </div>\n    <p style=\"margin-top:12px;\"><strong>Examiner Tip:</strong> When evaluating, always consider the specific business context. A large, well-established business may absorb one complaint without lasting damage — but a smaller business with a local reputation could be severely affected by a single product failure.</p>", "question": "According to the Examiner Tip, which type of business could be more severely affected by a single product failure?", "options": ["A smaller business with a local reputation", "A large, well-established business", "A business operating only online", "A business with multiple product lines"]}'::jsonb, '{"answer": 0, "explain": "The Examiner Tip states a smaller business with a local reputation could be severely affected by just one product failure, unlike a large established business."}'::jsonb),
('4-4-consumer-law:learn:fbb37418', '4-4-consumer-law', '4.4 Consumer Law', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Consumer Law in the Real World", "reading": "<div class=\"case-study-box\">\n      <h4>Case Study: Primark Ltd</h4>\n      <p>Primark is one of the UK''s largest fashion retailers, selling clothing and homeware at prices significantly lower than most competitors. It launched an online click and collect service in 2022.</p>\n      <p>Being a low-cost retailer does NOT exempt Primark from the Consumer Rights Act — all products must still be of satisfactory quality, fit for purpose, and as described.</p>\n      <p><strong>Takeaway:</strong> If Primark''s low-cost products are found to be ''not as described'' or not of satisfactory quality, the business could face a large volume of returns. Since Primark operates on very thin profit margins with high sales volume, excessive refunds could significantly hurt profitability. Negative social media coverage could further damage its reputation with price-conscious shoppers.</p>\n    </div>\n    <div class=\"case-study-box\">\n      <h4>Case Study: Pukka Pies Ltd</h4>\n      <p>Pukka Pies Ltd is a family-owned business with approximately 360 employees making high-quality savoury pies, sold in over 4,000 food stores nationwide. Three of its key values — delighting customers with quality pies and building trust with suppliers through food safety — directly support its compliance with consumer law.</p>\n      <p><strong>Takeaway:</strong> For a food manufacturer, the safety of goods is especially critical. Defective food products could cause illness or injury, triggering massive compensation claims under the Consumer Protection Act 1987 and catastrophic reputational damage — far outweighing the cost of maintaining quality standards.</p>\n    </div>\n    <div class=\"case-study-box\">\n      <h4>Case Study: Which? — The Consumers'' Champion</h4>\n      <p>Which? (formerly the Consumer''s Association) was founded in 1957 and works on behalf of customers, making them aware of their legal rights and testing products for compliance with the law. It has challenged supermarkets and banks to treat customers more fairly.</p>\n      <p><strong>Takeaway:</strong> Which? exists to make individual customers as powerful as the large organisations they deal with. Its ability to publicly challenge major businesses puts significant pressure on all firms to stay within the law — reinforcing that consumer law is actively enforced, not just theoretical.</p>\n    </div>", "question": "Approximately how many employees does Pukka Pies Ltd have, according to the case study?", "options": ["360", "4,000", "1,957", "100"]}'::jsonb, '{"answer": 0, "explain": "The case study states Pukka Pies Ltd is a family-owned business with approximately 360 employees."}'::jsonb),
('4-4-consumer-law:misc:09b1fd1e', '4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Consumer law requires goods to be of the ''best possible quality''.</p><p><strong>✅ The correct idea:</strong> Consumer law only requires ''satisfactory quality'' — a standard that reflects the price paid. A budget product does not need to be as good as a luxury product; it just needs to be appropriate for its price point.</p>", "question": "What standard of quality does consumer law actually require?", "options": ["Satisfactory quality, reflecting the price paid", "The best possible quality regardless of price", "Premium quality for all goods", "No legally defined quality standard"]}'::jsonb, '{"answer": 0, "explain": "Consumer law only requires ''satisfactory quality'' — a standard appropriate to the price paid, not the best possible quality."}'::jsonb),
('4-4-consumer-law:misc:a0219082', '4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing about fair wages, worker rights, or ethical suppliers will earn marks in a consumer law question.</p><p><strong>✅ The correct idea:</strong> Consumer law is specifically about protecting customers when they buy goods and services. Employment law covers workers'' rights. Ethical sourcing is a separate topic. The 2025 examiner''s report explicitly warned that candidates who wrote about wages or working conditions scored zero — even with good application and analysis.</p>", "question": "What did the 2025 examiner''s report say about answers discussing fair wages in a consumer law question?", "options": ["They scored zero despite good application and analysis", "They earned partial marks for application only", "They earned full marks if linked to reputation", "They earned knowledge marks but no application marks"]}'::jsonb, '{"answer": 0, "explain": "The examiner''s report explicitly warned that candidates writing about wages or working conditions scored zero, despite good application and analysis."}'::jsonb),
('4-4-consumer-law:misc:9df257ad', '4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The 30-day refund rule applies to all products, including downloaded music and apps.</p><p><strong>✅ The correct idea:</strong> The 30-day return rule does NOT apply to digital products such as downloaded music, films, or apps. For digital goods, customers can request a replacement or a price reduction of up to 100%.</p>", "question": "Does the 30-day full refund rule apply to downloaded music or apps?", "options": ["No — digital products are excluded from this rule", "Yes — it applies to all products including digital ones", "Only if the digital product cost over £50", "Only to downloaded films, not music or apps"]}'::jsonb, '{"answer": 0, "explain": "The 30-day rule does not apply to digital products; customers can instead request a replacement or a price reduction of up to 100%."}'::jsonb),
('4-4-consumer-law:misc:c492686e', '4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> After 30 days, customers have no rights at all and cannot make any further claims for faulty goods.</p><p><strong>✅ The correct idea:</strong> Customer rights continue beyond 30 days. Within 6 months, customers can claim a repair or replacement. After 6 months, they can still claim for up to six years if they can prove the fault existed at the time of purchase.</p>", "question": "What can a customer do after 30 days but within 6 months if goods turn out to be faulty?", "options": ["Claim a repair or replacement", "Nothing — rights end completely after 30 days", "Only claim a full refund", "Only complain to Which? magazine"]}'::jsonb, '{"answer": 0, "explain": "Within 6 months of purchase, customers can still claim a repair or replacement, as the fault is assumed to have existed at purchase."}'::jsonb),
('4-4-consumer-law:misc:b7870f0b', '4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Complying with consumer law is purely a cost to a business with no benefits.</p><p><strong>✅ The correct idea:</strong> Compliance brings significant benefits: improved reputation, fewer returns, increased customer loyalty, and avoidance of costly legal action. In 7-mark questions, you must evaluate both sides — benefits and drawbacks.</p>", "question": "What benefit does complying with consumer law bring to a business, according to this card?", "options": ["Improved reputation and increased customer loyalty", "Guaranteed exemption from all future legal claims", "Immediate elimination of production costs", "Automatic increase in market share"]}'::jsonb, '{"answer": 0, "explain": "Compliance brings benefits such as improved reputation, fewer returns, increased customer loyalty, and avoidance of costly legal action."}'::jsonb),
('4-4-consumer-law:misc:4b32c90f', '4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Consumer law only applies to large businesses with many customers.</p><p><strong>✅ The correct idea:</strong> Consumer law applies to ALL businesses selling goods or services to customers, regardless of size. A small family-run bakery must comply with the same Consumer Rights Act 2015 as a large supermarket like Tesco.</p>", "question": "Does consumer law apply only to large businesses with many customers?", "options": ["No — it applies to businesses of any size", "Yes — only businesses with over 100 employees", "Yes — only publicly listed companies", "No — only businesses that sell online"]}'::jsonb, '{"answer": 0, "explain": "Consumer law applies to all businesses selling goods or services, including a small family-run bakery, just as much as a large supermarket like Tesco."}'::jsonb),
('4-4-consumer-law:misc:005bbd49', '4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The Consumer Rights Act 2015 and the Consumer Protection Act 1987 are the same law.</p><p><strong>✅ The correct idea:</strong> These are two separate laws. The Consumer Rights Act 2015 covers the three requirements (satisfactory quality, fit for purpose, as described). The Consumer Protection Act 1987 specifically covers compensation claims when defective products cause death, injury, or damage.</p>", "question": "What is the key difference between the Consumer Rights Act 2015 and the Consumer Protection Act 1987?", "options": ["The 2015 Act covers quality; the 1987 Act covers compensation", "The two Acts are actually the same law with different names", "The 1987 Act only protects customers of food businesses", "The 2015 Act only protects buyers of digital products"]}'::jsonb, '{"answer": 0, "explain": "The two laws are separate: the 2015 Act covers satisfactory quality, fit for purpose and as described, while the 1987 Act covers compensation for death, injury, or damage caused by defective products."}'::jsonb),
('4-4-consumer-law:misc:0db124f9', '4-4-consumer-law', '4.4 Consumer Law', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Repeating earlier analysis points in a conclusion will earn evaluation marks in a 7-mark question.</p><p><strong>✅ The correct idea:</strong> Repeating earlier points in a conclusion earns zero evaluation marks. A good conclusion makes a new, justified judgement using specific context from the case study — using ''It depends on...'' or ''However, this is only the case if...'' style reasoning to show higher-level thinking.</p>", "question": "What happens if a student simply repeats earlier analysis points in a 7-mark conclusion?", "options": ["They earn zero evaluation marks", "They earn full evaluation marks for consistency", "They earn 1 mark for effort", "They earn analysis marks retroactively"]}'::jsonb, '{"answer": 0, "explain": "Repeating earlier points in a conclusion earns zero evaluation marks — a good conclusion must make a new, justified judgement."}'::jsonb),
('4-4-consumer-law:tips:4a960d9c', '4-4-consumer-law', '4.4 Consumer Law', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Point. Full Stop. Move On.", "reading": "\n          <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct, specific point. No explanation. No examples. No paragraphs — just one precise, accurate statement.</p>\n    \n          <p><strong>The Formula:</strong></p>\n          <ul>\n            <li>One clear, specific point = 1 mark ✅</li>\n            <li>A vague or general point = 0 marks ❌</li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n          <em>\"Consumer law protects customers.\"</em><br/>\n          Too vague — it doesn''t identify any specific protection.</p>\n    \n          <p><strong>✅ Good Answer (1 mark):</strong><br/>\n          <em>\"Goods must be of satisfactory quality.\"</em><br/>\n          Specific, accurate, and directly answers the question.</p>\n    \n          <p><strong>⚠️ Critical Examiner Warning:</strong> Many students confuse consumer law with employment law, writing about fair wages or working conditions. This scores ZERO — no matter how detailed the answer is. The mark scheme explicitly states: \"No further marks can be gained without understanding\" of what consumer law actually requires.</p>\n        ", "question": "Why does ''Consumer law protects customers'' score 0 marks as an answer to a 1-mark identify question?", "options": ["It is too vague to identify a specific protection", "It wrongly confuses consumer law with employment law", "It is factually incorrect about consumer rights", "It is too long for a 1-mark question"]}'::jsonb, '{"answer": 0, "explain": "The card explains this answer is too vague — it doesn''t identify any specific protection required under consumer law."}'::jsonb),
('4-4-consumer-law:tips:14fa8514', '4-4-consumer-law', '4.4 Consumer Law', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Identify It, Then Apply It to the Business", "reading": "\n          <p>A 2-mark <strong>''Explain''</strong> question requires you to name an impact of consumer law AND link it specifically to the business named in the question. Two clear steps — one per mark.</p>\n    \n          <p><strong>The 2-Step Formula:</strong></p>\n          <ul>\n            <li><strong>Step 1 — Identify the impact (1 mark):</strong> Name a specific way consumer law affects businesses.</li>\n            <li><strong>Step 2 — Apply to the specific business (1 mark):</strong> Use a detail from the case study to show how this applies to that particular business.</li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n          <em>\"Consumer law could affect Tesco''s reputation.\"</em><br/>\n          Identifies an impact but does not apply it to Tesco specifically using case study detail.</p>\n    \n          <p><strong>✅ Good Answer (2 marks):</strong><br/>\n          <em>\"If Tesco plc sells products which are not as described (K — 1 mark), it could receive poor press coverage leading to a loss of sales (APP — 1 mark applied to Tesco as a major UK retailer).\"</em></p>\n    \n          <p><strong>🚫 Knowledge Dumping Alert:</strong> You only need ONE impact, explained and applied to the business. Writing everything you know about consumer law will NOT earn more marks — only one applied point is needed.</p>\n        ", "question": "What are the two steps required to earn full marks on a 2-mark ''Explain'' question?", "options": ["Identify an impact, then apply it to the business", "State three separate requirements of consumer law", "Give two direct quotes from the case study", "Identify an impact and then evaluate its importance"]}'::jsonb, '{"answer": 0, "explain": "The 2-step formula is: Step 1 identify a specific impact, Step 2 apply it to the named business using case study detail."}'::jsonb),
('4-4-consumer-law:tips:1b39e9f4', '4-4-consumer-law', '4.4 Consumer Law', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n          <p>A 3-mark <strong>''Analyse''</strong> question is the most common extended question on consumer law. You must follow a strict 3-step structure — missing any one step costs you marks. And without demonstrating understanding of consumer law first, you cannot earn ANY further marks.</p>\n    \n          <p><strong>The 3-Step Formula:</strong></p>\n          <ul>\n            <li><strong>Step 1 — Understanding (U — 1 mark):</strong> State a specific requirement of consumer law: \"Consumer law requires goods to be of satisfactory quality / fit for purpose / as described.\"</li>\n            <li><strong>Step 2 — Application (APP — 1 mark):</strong> Link directly to the specific business in the case study using a quoted or paraphrased detail from the text.</li>\n            <li><strong>Step 3 — Analysis (AN — 1 mark):</strong> State the financial or operational impact: costs, profit, reputation, or sales. Keep asking \"So what does this mean for the business?\" until you hit a bottom-line impact.</li>\n          </ul>\n    \n          <p><strong>⚠️ Zero-Mark Trap — Consumer Law vs. Ethical Issues:</strong> Writing about wages, working conditions, or ethical sourcing instead of consumer law will score ZERO — even with perfect application and analysis. The examiner''s report confirms many candidates scored zero for this exact reason.</p>\n    \n          <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n          <em>\"One impact of consumer law is that Primark must pay workers a fair wage. Primark sells at cheaper prices than most retailers, so this increases costs.\"</em><br/>\n          This confuses consumer law with employment law. ZERO marks despite having application and analysis.</p>\n    \n          <p><strong>✅ Good Answer (3 marks):</strong><br/>\n          <em>\"Consumer law requires goods to be ''not as described'' (U — 1 mark). If Primark Ltd sells clothing or homeware products that do not match their online description (APP — 1 mark to Primark as a low-price retailer), the business could face large volumes of returned goods. Since Primark operates on very tight profit margins, the additional refund costs could significantly reduce overall profitability (AN — 1 mark).\"</em></p>\n    \n          <p><strong>Sentence Starters to use:</strong></p>\n          <ul>\n            <li><em>\"Consumer law requires goods to be... (U)\"</em></li>\n            <li><em>\"In the case of [Business]... / Because the text states that... (APP)\"</em></li>\n            <li><em>\"This will lead to... / As a result, the business will... / This reduces... meaning... (AN)\"</em></li>\n          </ul>\n        ", "question": "What are the three steps of the ''Holy Trinity'' structure for a 3-mark analyse question?", "options": ["Understanding, Application, Analysis", "Knowledge, Evaluation, Justification", "Identify, Explain, Conclude", "Application, Evaluation, Reasoning"]}'::jsonb, '{"answer": 0, "explain": "The 3-step formula for a 3-mark analyse question is U (Understanding) → APP (Application) → AN (Analysis)."}'::jsonb),
('4-4-consumer-law:tips:40981f7e', '4-4-consumer-law', '4.4 Consumer Law', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate / Discuss — 7 marks — Four Paragraphs: Two Impacts + a Justified Conclusion", "reading": "\n          <p>A 7-mark question is the most demanding on this topic. You need two separately analysed impacts (with case study application) and a justified evaluative conclusion. Marks: APP (2) + AN (2) + EV (3).</p>\n    \n          <p><strong>The 4-Paragraph Structure:</strong></p>\n          <ul>\n            <li><strong>Para 1 — K & U:</strong> Introduce a key requirement of consumer law and explain what this means for a business in general terms.</li>\n            <li><strong>Para 2 — APP & AN (Impact 1):</strong> Apply your first point to the case study using specific details from the text. Analyse the specific financial or operational impact on the business.</li>\n            <li><strong>Para 3 — APP & AN (Impact 2):</strong> Introduce a second, different impact. Apply and analyse in the same way — it must be a different consequence from Para 2.</li>\n            <li><strong>Para 4 — Evaluation (3 marks):</strong>\n              <ul>\n                <li><strong>Decision (1 mark):</strong> A clear, direct judgement — e.g. \"Consumer law is very important to QUA\" or \"It is more beneficial to comply than not.\"</li>\n                <li><strong>Context (1 mark):</strong> Justify your decision using a specific detail from the case study.</li>\n                <li><strong>Impact/Reasoning (1 mark):</strong> Use a ''depends on'' or ''however'' argument to show nuanced thinking — e.g. \"However, this depends on whether QUA can resolve the quality issues quickly before more negative coverage spreads.\"</li>\n              </ul>\n            </li>\n          </ul>\n    \n          <p><strong>⚠️ Evaluation Warning:</strong> A conclusion that simply repeats your earlier points scores ZERO evaluation marks. Your conclusion must make a NEW, justified judgement that goes beyond what you said in Paragraphs 2 and 3.</p>\n    \n          <p><strong>Evaluation Sentence Starters:</strong></p>\n          <ul>\n            <li><em>\"Overall, I believe consumer law is [very important / more beneficial / more harmful] to [Business] because...\" (Decision)</em></li>\n            <li><em>\"This is particularly significant because the text states that... (Context)\"</em></li>\n            <li><em>\"However, the full impact will depend on whether... / This matters more because the business... (Reasoning)\"</em></li>\n          </ul>\n        ", "question": "How many marks are allocated to Evaluation (EV) in a 7-mark ''Evaluate/Discuss'' question?", "options": ["3 marks", "2 marks", "4 marks", "7 marks"]}'::jsonb, '{"answer": 0, "explain": "The 7 marks split as APP (2) + AN (2) + EV (3), so Evaluation is worth 3 marks."}'::jsonb),
('4-4-consumer-law:tips:f427ceea', '4-4-consumer-law', '4.4 Consumer Law', 'tips', 'mcq', 1, '{"readingTitle": "Critical Warning — All Question Types — Consumer Law ≠ Ethical Behaviour. Know the Difference.", "reading": "\n          <p>This is the <strong>single most common reason students score zero</strong> on consumer law questions. The examiner''s report explicitly highlighted this as the major failure point across multiple exam sittings.</p>\n    \n          <p><strong>✅ Consumer Law — Legal Requirements (Scoreable):</strong></p>\n          <ul>\n            <li>Goods must be of satisfactory quality ✅</li>\n            <li>Goods must be fit for purpose ✅</li>\n            <li>Goods must be as described ✅</li>\n            <li>Compensation rights for defective or dangerous products ✅</li>\n            <li>30-day return right for faulty goods ✅</li>\n          </ul>\n    \n          <p><strong>❌ NOT Consumer Law — Ethical / Employment Issues (Scores Zero):</strong></p>\n          <ul>\n            <li>Paying workers a fair or living wage ❌</li>\n            <li>Using sustainable or ethical suppliers ❌</li>\n            <li>Reducing environmental impact ❌</li>\n            <li>Treating employees fairly ❌</li>\n            <li>Supporting local communities ❌</li>\n          </ul>\n    \n          <p><strong>📋 Direct from the 2025 Examiner''s Report:</strong><br/>\n          <em>\"Many candidates did not understand consumer law and mixed it up with employment law (many referred to employee rights, fair pay, or working conditions) or ethical considerations. These candidates could not be credited with any marks, despite having application and analysis, due to not specifying any correct understanding.\"</em></p>\n    \n          <p><strong>The Simple Test:</strong> Can you link your point back to \"satisfactory quality,\" \"fit for purpose,\" or \"as described\"? If not, you are likely writing about the wrong topic. Stop and refocus.</p>\n        ", "question": "What is the ''Simple Test'' recommended to check whether a point is genuinely about consumer law?", "options": ["Can the point be linked to one of the three requirements?", "Does it mention a named business from the case study?", "Is the point longer than two written sentences?", "Does it directly reference the Consumer Protection Act?"]}'::jsonb, '{"answer": 0, "explain": "The Simple Test checks whether a point can be linked back to one of the three requirements: satisfactory quality, fit for purpose, or as described."}'::jsonb),
