('4-4-consumer-law:match:b3cfb40c', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consumer Law”?", "options": ["An act of parliament giving customers protection when buying goods and services: they must be of satisfactory quality, fit for purpose, and as described.", "The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015.", "Goods must not be damaged or faulty when bought; the quality expected should reflect the price paid.", "Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it."]}'::jsonb, '{"answer": 1, "explain": "“Consumer Law” means: The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015."}'::jsonb),
('4-4-consumer-law:match:2c51f48a', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consumer Rights Act 2015”?", "options": ["Goods must not be damaged or faulty when bought; the quality expected should reflect the price paid.", "Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it.", "An act of parliament giving customers protection when buying goods and services: they must be of satisfactory quality, fit for purpose, and as described.", "Goods must be exactly as described or advertised — receiving the wrong colour or specification breaks this requirement."]}'::jsonb, '{"answer": 2, "explain": "“Consumer Rights Act 2015” means: An act of parliament giving customers protection when buying goods and services: they must be of satisfactory quality, fit for purpose, and as described."}'::jsonb),
('4-4-consumer-law:match:00a8fb7a', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Satisfactory Quality”?", "options": ["Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it.", "Goods must be exactly as described or advertised — receiving the wrong colour or specification breaks this requirement.", "Goods must not be damaged or faulty when bought; the quality expected should reflect the price paid.", "What customers say and feel about a business; damage to a reputation can seriously reduce sales and threaten business survival."]}'::jsonb, '{"answer": 2, "explain": "“Satisfactory Quality” means: Goods must not be damaged or faulty when bought; the quality expected should reflect the price paid."}'::jsonb),
('4-4-consumer-law:match:5727102a', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fit for Purpose”?", "options": ["Goods must be exactly as described or advertised — receiving the wrong colour or specification breaks this requirement.", "Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it.", "What customers say and feel about a business; damage to a reputation can seriously reduce sales and threaten business survival.", "A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987."]}'::jsonb, '{"answer": 1, "explain": "“Fit for Purpose” means: Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it."}'::jsonb),
('4-4-consumer-law:match:cda1cf20', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “As Described”?", "options": ["What customers say and feel about a business; damage to a reputation can seriously reduce sales and threaten business survival.", "A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987.", "Goods must be exactly as described or advertised — receiving the wrong colour or specification breaks this requirement.", "Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury."]}'::jsonb, '{"answer": 2, "explain": "“As Described” means: Goods must be exactly as described or advertised — receiving the wrong colour or specification breaks this requirement."}'::jsonb),
('4-4-consumer-law:match:d749cf3f', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Reputation”?", "options": ["What customers say and feel about a business; damage to a reputation can seriously reduce sales and threaten business survival.", "A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987.", "Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.", "Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products."]}'::jsonb, '{"answer": 0, "explain": "“Reputation” means: What customers say and feel about a business; damage to a reputation can seriously reduce sales and threaten business survival."}'::jsonb),
('4-4-consumer-law:match:a1e68ff5', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Compensation”?", "options": ["Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.", "A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987.", "Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products.", "Processes a business uses to check that all goods meet the required quality standards before reaching the customer."]}'::jsonb, '{"answer": 1, "explain": "“Compensation” means: A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987."}'::jsonb),
('4-4-consumer-law:match:e4d73b27', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consumer Protection Act 1987”?", "options": ["Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products.", "Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.", "Processes a business uses to check that all goods meet the required quality standards before reaching the customer.", "Products that are faulty, unsafe, or fail to meet the legal standards set by the Consumer Rights Act 2015."]}'::jsonb, '{"answer": 1, "explain": "“Consumer Protection Act 1987” means: Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury."}'::jsonb),
('4-4-consumer-law:match:5588fc2b', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “30-Day Return Rule”?", "options": ["Processes a business uses to check that all goods meet the required quality standards before reaching the customer.", "Products that are faulty, unsafe, or fail to meet the legal standards set by the Consumer Rights Act 2015.", "Online platforms that allow customers to publicly voice complaints about defective goods, rapidly damaging a business''s reputation.", "Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products."]}'::jsonb, '{"answer": 3, "explain": "“30-Day Return Rule” means: Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products."}'::jsonb),
('4-4-consumer-law:match:e67faf01', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quality Assurance”?", "options": ["Products that are faulty, unsafe, or fail to meet the legal standards set by the Consumer Rights Act 2015.", "Online platforms that allow customers to publicly voice complaints about defective goods, rapidly damaging a business''s reputation.", "The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015.", "Processes a business uses to check that all goods meet the required quality standards before reaching the customer."]}'::jsonb, '{"answer": 3, "explain": "“Quality Assurance” means: Processes a business uses to check that all goods meet the required quality standards before reaching the customer."}'::jsonb),
('4-4-consumer-law:match:79ed06d8', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Defective Goods”?", "options": ["Products that are faulty, unsafe, or fail to meet the legal standards set by the Consumer Rights Act 2015.", "Online platforms that allow customers to publicly voice complaints about defective goods, rapidly damaging a business''s reputation.", "The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015.", "An act of parliament giving customers protection when buying goods and services: they must be of satisfactory quality, fit for purpose, and as described."]}'::jsonb, '{"answer": 0, "explain": "“Defective Goods” means: Products that are faulty, unsafe, or fail to meet the legal standards set by the Consumer Rights Act 2015."}'::jsonb),
('4-4-consumer-law:match:30fa027c', '4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Social Media”?", "options": ["Online platforms that allow customers to publicly voice complaints about defective goods, rapidly damaging a business''s reputation.", "The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015.", "An act of parliament giving customers protection when buying goods and services: they must be of satisfactory quality, fit for purpose, and as described.", "Goods must not be damaged or faulty when bought; the quality expected should reflect the price paid."]}'::jsonb, '{"answer": 0, "explain": "“Social Media” means: Online platforms that allow customers to publicly voice complaints about defective goods, rapidly damaging a business''s reputation."}'::jsonb),
('4-5-business-location:exam:992f2c36', '4-5-business-location', '4.5 Business Location', 'exam', 'mcq', 1, '{"num": "Q1", "question": "In the context of business operations, what does the phrase ''proximity to market'' refer to?", "options": ["Advertising the business specifically to those who live in the local area", "Locating a business close to its potential customers", "Only employing workers who are part of the local community", "Working on a site that is close to a source of raw materials"], "hint": "Think about what ''proximity'' means — it means ''nearness to''. What does ''market'' refer to in a business context?", "starter": "Proximity to market means locating a business close to..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Locating a business close to its potential customers</h5><p><strong>Why B is correct:</strong> ''Proximity to market'' is a specific business location term meaning nearness to where the business''s customers are. It encourages businesses to locate where they can access the most potential buyers.</p><ul><li><strong>❌ A is wrong:</strong> Advertising to local people is a marketing decision, not a location factor.</li><li><strong>❌ C is wrong:</strong> Employing local workers relates to proximity to labour, not the market.</li><li><strong>❌ D is wrong:</strong> Being near a source of raw materials is the separate factor of ''proximity to raw materials.''</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-5-business-location:exam:3f1bdc19', '4-5-business-location', '4.5 Business Location', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Which one of the following is the most likely reason for a greeting card manufacturer to locate its factory on an out-of-town industrial estate?", "options": ["Council incentives offering reduced business rates", "Greeting cards are destroyed if they get wet during transportation", "Lots of people who work on the industrial estate will buy cards", "The need to be close to the market because customers are unwilling to travel"], "hint": "Greeting cards are small, lightweight, and easy to transport. The business does not need to be near its final customers. Think about what advantage an out-of-town industrial estate offers over a high-street location.", "starter": "The most likely reason is reduced costs, specifically..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Council incentives offering reduced business rates</h5><p><strong>Why A is correct:</strong> A greeting card manufacturer does not need to be near its final customers — cards are small, durable, and easy to transport nationally. An out-of-town industrial estate offers lower costs, and council incentives such as reduced business rates make it even more financially attractive.</p><ul><li><strong>❌ B is wrong:</strong> Greeting cards are packaged and not significantly damaged during normal transportation — this is not a valid reason for choosing an industrial estate.</li><li><strong>❌ C is wrong:</strong> Industrial estate workers are not the primary market for greeting cards. This would not justify the location decision.</li><li><strong>❌ D is wrong:</strong> The question describes an out-of-town location, which directly contradicts the idea of being close to customers. Customers do not travel to a factory to purchase cards.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-5-business-location:exam:d1bca7c1', '4-5-business-location', '4.5 Business Location', 'exam', 'mcq', 1, '{"num": "Q3", "question": "Which one of the following is a benefit of locating a tomato farm near to a ready supply of labour?", "options": ["Ease of recruitment of tomato pickers", "Personal contact with supermarket buyers", "Sales of fresh tomatoes are likely to increase", "The tomatoes will not need to be transported"], "hint": "Focus on what ''near to a ready supply of labour'' means. Labour = workers. What specific benefit does having workers nearby provide for a farm?", "starter": "A benefit of locating near a supply of labour is that it makes it easier to..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Ease of recruitment of tomato pickers</h5><p><strong>Why A is correct:</strong> Locating near a ready supply of labour means the business can easily recruit the workers it needs. For a tomato farm, this means pickers are available locally, reducing recruitment costs and labour shortages during harvest time.</p><ul><li><strong>❌ B is wrong:</strong> Personal contact with supermarket buyers relates to proximity to the market (customers), not to labour.</li><li><strong>❌ C is wrong:</strong> Increased tomato sales relate to market proximity, not the labour supply.</li><li><strong>❌ D is wrong:</strong> Tomatoes still need to be transported to supermarkets and shops regardless of where the farm is relative to its workers. Labour location does not affect transportation requirements.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-5-business-location:exam:2e338ffd', '4-5-business-location', '4.5 Business Location', 'exam', 'mcq', 1, '{"num": "Q10", "question": "Which of these is NOT a reason for a business locating near to its market?", "options": ["It produces a large finished product", "It uses bulky raw materials to produce a smaller, finished product", "Its customers are not likely to travel far, nor shop over the internet, to buy what it sells", "It sells fresh products such as cream cakes"], "hint": "Think about which option describes locating near RAW MATERIALS rather than near the MARKET. Which one is actually the opposite reason?", "starter": "The answer is... because this is a reason to locate near [raw materials / the market], not near..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — It uses bulky raw materials to produce a smaller, finished product</h5><p><strong>Why B is NOT a reason to locate near the market:</strong> Using bulky raw materials to produce a smaller finished product is a reason to locate near the RAW MATERIALS — not near customers. The logic is that transporting heavy raw materials long distances is more expensive than transporting the lighter finished product.</p><ul><li><strong>❌ A is a valid reason to locate near the market:</strong> Producing a large finished product makes it expensive to transport — so locating near the buyer keeps delivery costs low.</li><li><strong>❌ C is a valid reason:</strong> If customers won''t travel or shop online, the business must go to where the customers are.</li><li><strong>❌ D is a valid reason:</strong> Fresh/perishable products (like cream cakes) must reach customers quickly — locating near the market prevents spoilage and reduces waste.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-5-business-location:exam:015cfb9c', '4-5-business-location', '4.5 Business Location', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Which one of these statements about business location is NOT true?", "options": ["Firms that produce small, finished products are best locating near to their market", "Governments often influence the location of businesses so that they can reduce unemployment and raise incomes in certain parts of the country", "Low-cost locations are important for every single producer", "Where a business locates is often influenced by more than one location factor"], "hint": "Think about whether ALL businesses need to prioritise keeping costs low, or whether some businesses prioritise other factors — like prestige, skilled labour, or access to customers — above minimising costs.", "starter": "The statement that is NOT true is C, because not all businesses..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Low-cost locations are important for every single producer</h5><p><strong>Why C is NOT true:</strong> Low-cost locations are important for many businesses, but NOT every single producer. Some businesses — such as luxury brands, specialist service providers, or those requiring highly skilled labour near universities — prioritise location quality, skilled workers, or proximity to customers above cost minimisation.</p><ul><li><strong>A is true:</strong> Small, light finished products are cheap to transport, so proximity to the market matters less. However, it may still be beneficial for customer accessibility.</li><li><strong>B is true:</strong> Governments use enterprise zones, grants, and freeports to encourage businesses to locate in high-unemployment areas.</li><li><strong>D is true:</strong> Most location decisions involve weighing up multiple factors simultaneously — costs, labour, transport, customers, and government incentives.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-5-business-location:exam:3c196127', '4-5-business-location', '4.5 Business Location', 'exam', 'mcq', 1, '{"num": "Q12", "question": "A firm has identified four possible locations. Based on the figures available, which offers the lowest cost per unit produced?", "options": ["Site W: Output 10,000 units/year. Annual rental £30,000. Annual wages £80,000.", "Site X: Output 12,000 units/year. Annual rental £42,000. Annual wages £102,000.", "Site Y: Output 11,000 units/year. Annual rental £34,000. Annual wages £81,500.", "Site Z: Output 9,000 units/year. Annual rental £32,000. Annual wages £71,500."], "hint": "Calculate: Cost per unit = (Annual rent + Annual wages) ÷ Units produced. Work this out for all four sites, then compare.", "starter": "Cost per unit = (rent + wages) ÷ output. I will calculate each site: W = £___ / 10,000 = ... X = £___ / 12,000 = ... Y = £___ / 11,000 = ... Z = £___ / 9,000 = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Site Y (£10.50 per unit)</h5><p><strong>Calculations (Cost per unit = Total costs ÷ Output):</strong></p><ul><li>Site W: (£30,000 + £80,000) ÷ 10,000 = £110,000 ÷ 10,000 = <strong>£11.00 per unit</strong></li><li>Site X: (£42,000 + £102,000) ÷ 12,000 = £144,000 ÷ 12,000 = <strong>£12.00 per unit</strong></li><li>Site Y: (£34,000 + £81,500) ÷ 11,000 = £115,500 ÷ 11,000 = <strong>£10.50 per unit ✅ LOWEST</strong></li><li>Site Z: (£32,000 + £71,500) ÷ 9,000 = £103,500 ÷ 9,000 = <strong>£11.50 per unit</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-5-business-location:exam:209670e3', '4-5-business-location', '4.5 Business Location', 'exam', 'mcq', 1, '{"num": "Q13", "question": "An online retailer sells goods across the UK. When deciding where to locate a warehouse, which of the following would NOT be important?", "options": ["Having good access to the road network", "Being near a supply of raw materials", "Being near to most of its customers", "Being in a location where there is a ready supply of labour"], "hint": "An online retailer SELLS finished goods — it does not manufacture them. Think about which of these factors would only matter for a manufacturing business, not a warehouse.", "starter": "The factor that would NOT be important for an online retailer''s warehouse is... because an online retailer does not..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Being near a supply of raw materials (C is also accepted)</h5><p><strong>Why B is not important:</strong> An online retailer sells finished goods to customers — it does not manufacture anything, so it has no need for raw materials. Proximity to raw materials is completely irrelevant to a warehouse operation.</p><p><strong>Why C may also be accepted:</strong> An online retailer delivers to customers nationally — it does not need to be near most of its customers since deliveries are handled by couriers. Warehouse location is more about transport infrastructure than customer geography.</p><ul><li><strong>❌ A is important:</strong> Good road network access is essential for receiving stock from suppliers and dispatching customer orders efficiently.</li><li><strong>❌ D is important:</strong> Online warehouses require many workers to pick, pack, and dispatch orders — labour availability is critical to operations.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('4-5-business-location:mcq:992f2c36', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "In the context of business operations, what does the phrase ''proximity to market'' refer to?", "options": ["Advertising the business specifically to those who live in the local area", "Locating a business close to its potential customers", "Only employing workers who are part of the local community", "Working on a site that is close to a source of raw materials"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. ''Proximity to market'' means locating a business near its potential customers. A relates to marketing, C relates to proximity to labour, and D refers to proximity to raw materials — all separate location factors."}'::jsonb),
('4-5-business-location:mcq:3f1bdc19', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "Which one of the following is the most likely reason for a greeting card manufacturer to locate its factory on an out-of-town industrial estate?", "options": ["Council incentives offering reduced business rates", "Greeting cards are destroyed if they get wet during transportation", "Lots of people who work on the industrial estate will buy cards", "The need to be close to the market because customers are unwilling to travel"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. A greeting card manufacturer does not need to be near its final customers — cards are small and easy to transport. An industrial estate offers lower costs, and council incentives such as reduced business rates make it even more attractive. B is not valid (cards are packaged), C is incorrect (industrial workers are not a significant market), and D contradicts the out-of-town choice."}'::jsonb),
('4-5-business-location:mcq:d1bca7c1', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "Which one of the following is a benefit of locating a tomato farm near to a ready supply of labour?", "options": ["Ease of recruitment of tomato pickers", "Personal contact with supermarket buyers", "Sales of fresh tomatoes are likely to increase", "The tomatoes will not need to be transported"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. Locating near a supply of labour means the farm can easily recruit workers — in this case, tomato pickers. B relates to proximity to the market (customers), not labour. C is also about market proximity. D is incorrect — tomatoes still need to be transported to supermarkets regardless of where the farm is relative to its workers."}'::jsonb),
('4-5-business-location:mcq:e5ac4ca0', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a reason for a business to locate near to its market?", "options": ["It produces a large finished product", "It uses bulky raw materials to produce a smaller, finished product", "Its customers are not likely to travel far, nor shop over the internet", "It sells fresh products such as cream cakes"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Using bulky raw materials to produce a smaller finished product is a reason to locate near RAW MATERIALS, not near the market. The logic is that it''s cheaper to transport the light finished product than the heavy raw material. A, C, and D are all valid reasons to locate near the market."}'::jsonb),
('4-5-business-location:mcq:015cfb9c', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "Which one of these statements about business location is NOT true?", "options": ["Firms that produce small, finished products are best locating near to their market", "Governments often influence the location of businesses to reduce unemployment in certain areas", "Low-cost locations are important for every single producer", "Where a business locates is often influenced by more than one location factor"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. It is NOT true that low-cost locations are important for every single producer. Some businesses prioritise skilled labour, prestige location, or proximity to customers over minimising costs (e.g., a luxury hotel in central London). A, B, and D are all true statements."}'::jsonb),
('4-5-business-location:mcq:50c92a48', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "A firm is comparing four possible locations. Which site offers the lowest cost per unit produced?", "options": ["Site W: 10,000 units/year, rent £30,000, wages £80,000 → £11.00 per unit", "Site X: 12,000 units/year, rent £42,000, wages £102,000 → £12.00 per unit", "Site Y: 11,000 units/year, rent £34,000, wages £81,500 → £10.50 per unit", "Site Z: 9,000 units/year, rent £32,000, wages £71,500 → £11.50 per unit"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Site Y. Cost per unit = (Total costs) ÷ Output. Site W: £110,000 ÷ 10,000 = £11.00. Site X: £144,000 ÷ 12,000 = £12.00. Site Y: £115,500 ÷ 11,000 = £10.50 ✅. Site Z: £103,500 ÷ 9,000 = £11.50. Site Y has the lowest cost per unit."}'::jsonb),
('4-5-business-location:mcq:209670e3', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "An online retailer sells goods across the UK. When deciding where to locate a warehouse, which of the following would NOT be important?", "options": ["Having good access to the road network", "Being near a supply of raw materials", "Being near to most of its customers", "Being in a location where there is a ready supply of labour"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B (and C is also accepted). An online retailer sells finished goods — it does not manufacture, so proximity to raw materials is irrelevant. Being near most customers (C) is also less critical since national delivery handles distribution. Good road access (A) and available labour (D) are both essential for a warehouse operation."}'::jsonb),
('4-5-business-location:mcq:d2cf3d6f', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "Cambridge Research Biochemicals (CRB) moved production from Cambridge to Billingham in Teesside. What was the primary reason?", "options": ["The government gave CRB a large grant specifically to relocate", "CRB''s main customers were all based in the north of England", "Production costs — especially rent and labour — were much lower in Teesside", "Teesside had better transport links to international markets"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. The primary reason was significantly lower costs — rents in Billingham were only 10% of those in Cambridge, and labour was cheaper too. CRB did later receive a ''Let''s Grow'' grant (A), but this was a secondary benefit that helped fund the move to the enterprise zone in 2014, not the original reason for relocating in 1999."}'::jsonb),
('4-5-business-location:mcq:3bcd0c27', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "Why might a cheese manufacturer choose to locate near to dairy farms?", "options": ["To benefit from government enterprise zone grants", "To reduce the cost and distance of transporting bulky raw materials (milk)", "To be near to its final customers in supermarkets", "To access a supply of skilled cheese-making labour in rural areas"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Milk is a bulky, perishable raw material. Locating close to dairy farms reduces transport costs and spoilage risk. It also reduces the carbon footprint of the business. This is proximity to raw materials. C relates to the market, A to government, and D to labour — all separate location factors."}'::jsonb),
('4-5-business-location:mcq:ee6daa45', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "What benefits do UK Enterprise Zones offer to businesses that locate there?", "options": ["Free land and premises, unlimited government funding, and exemption from all taxes", "Reduced business rates, lower taxes on investment, superfast broadband, and faster planning approvals", "Guaranteed customers, government contracts, and free advertising", "Exemption from employment law and the right to pay below minimum wage"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Enterprise zones offer a specific package: reduced business rates (taxes on premises), higher capital allowances (lower taxes when businesses invest), superfast broadband, faster planning approvals, and sometimes ready-built premises. They do not offer free land, unlimited funding, or exemptions from employment law."}'::jsonb),
('4-5-business-location:mcq:48ca1545', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "Lo-Cost Rental, which offers cheap low-specification cars, is considering locating at Heathrow Airport. What is the GREATEST concern?", "options": ["The airport only has 75 million passengers per year — not enough customers", "The high cost of renting a service desk and parking spaces makes profitability very difficult", "There are no competitors at Heathrow, so demand is uncertain", "The airport''s road links are too poor to operate a car rental business"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. The greatest concern for a LOW-COST company is that operating costs at Heathrow (service desk rental and parking) are very high. This makes it almost impossible to maintain low rental prices while remaining profitable. Competition (from Hertz, Avis etc.) is also a concern, but costs are the primary issue for Lo-Cost''s business model."}'::jsonb),
('4-5-business-location:mcq:ff9020dd', '4-5-business-location', '4.5 Business Location', 'mcq', 'mcq', 1, '{"question": "''Silicon Fen'' is an area near Cambridge. Why might an ICT company choose to locate there?", "options": ["It is close to major sea ports for importing computer hardware", "The government offers free land to all technology businesses in the area", "There is a concentration of skilled ICT workers and technology firms already based there", "The area has the lowest business rates of any location in the UK"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Silicon Fen is attractive to ICT firms because of its cluster of existing technology businesses and the proximity to Cambridge University, which produces large numbers of highly skilled technology graduates. This makes recruitment of skilled workers much easier — a key location factor for ICT businesses."}'::jsonb),
('4-5-business-location:tf:2ccfcb27', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "For many businesses, the decision of where to locate is one of the most important decisions they make."}'::jsonb, '{"answer": true, "explain": "TRUE. Making the right location decision can help a business flourish and become very successful. Making the wrong decision can make success very difficult. Location affects costs, access to customers, labour supply, and raw material access."}'::jsonb),
('4-5-business-location:tf:daefe044', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "Low-cost locations are important for every single type of business."}'::jsonb, '{"answer": false, "explain": "FALSE. While cost is important for many businesses, it is not the top priority for every business. Some prioritise skilled labour, proximity to customers, or prestigious location above minimising costs — a luxury hotel in central London is an example."}'::jsonb),
('4-5-business-location:tf:5173def2', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "Proximity to raw materials is most important for businesses that use bulky materials to produce a smaller, lighter finished product."}'::jsonb, '{"answer": true, "explain": "TRUE. When raw materials are bulky and the finished product is lighter (e.g., wheat → flour, milk → cheese), it is more cost-effective to locate the factory near the raw materials and transport the finished product — not the other way around."}'::jsonb),
('4-5-business-location:tf:bfdf784a', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "Online retailers like Amazon need to locate their warehouses close to customers rather than near transport infrastructure."}'::jsonb, '{"answer": false, "explain": "FALSE. Online retailers prioritise access to the road/rail network and a supply of labour for their warehouses. Being near customers is far less important than having a location that allows efficient national delivery."}'::jsonb),
('4-5-business-location:tf:d1d2e53c', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "Enterprise zones offer incentives such as reduced business rates and faster planning approvals to attract businesses."}'::jsonb, '{"answer": true, "explain": "TRUE. UK enterprise zones offer a package of benefits: reduced business rates, higher capital allowances (lower taxes on investment), superfast broadband, faster planning approvals, and sometimes ready-built premises."}'::jsonb),
('4-5-business-location:tf:0c35db04', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "A business will always be influenced by only one location factor when making its location decision."}'::jsonb, '{"answer": false, "explain": "FALSE. It is rarely only one factor — usually it is a combination. A bakery may consider proximity to customers AND transport costs. A manufacturer may weigh raw material access, labour supply, AND government incentives simultaneously."}'::jsonb),
('4-5-business-location:tf:5be6ae5d', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "Cambridge Research Biochemicals (CRB) moved to Teesside partly because rents there were only 10% of those in Cambridge."}'::jsonb, '{"answer": true, "explain": "TRUE. The case study explicitly states that rents in Billingham are only 10% of those in Cambridge — a massive cost saving that made the relocation financially compelling for CRB."}'::jsonb),
('4-5-business-location:tf:68131507', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "Service businesses such as hairdressers and dentists rarely need to consider proximity to customers when choosing a location."}'::jsonb, '{"answer": false, "explain": "FALSE. Service businesses like hairdressers and dentists MUST locate near their customers because the service is delivered in person. Unlike manufacturers, they cannot transport their service — the customer must come to them, so proximity to potential customers is essential."}'::jsonb),
('4-5-business-location:tf:5c457965', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "The Northern Powerhouse initiative aims to encourage business growth across the north of England from Liverpool to Hull."}'::jsonb, '{"answer": true, "explain": "TRUE. The Northern Powerhouse is a government scheme investing in infrastructure and providing funding across northern regions from Liverpool in the west to Hull in the east, aiming to create jobs and raise incomes."}'::jsonb),
('4-5-business-location:tf:02713087', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "Locating near raw material suppliers always reduces a business''s carbon footprint."}'::jsonb, '{"answer": true, "explain": "TRUE. Shorter supply chains mean less transportation, which means fewer carbon emissions. Dewlay Cheesemakers, for example, sources milk from farms within six miles and uses this as a marketing advantage — highlighting its environmental credentials."}'::jsonb),
('4-5-business-location:tf:4ad5f951', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "The Wool Warehouse chose a high street location to benefit from maximum footfall from passing shoppers."}'::jsonb, '{"answer": false, "explain": "FALSE. The Wool Warehouse deliberately chose a WAREHOUSE (not a high street shop) to enter the online market easily, keep costs low, and serve customers nationally. High street locations were irrelevant to their online business model."}'::jsonb),
('4-5-business-location:tf:53caa780', '4-5-business-location', '4.5 Business Location', 'tf', 'tf', 1, '{"question": "In 2021, the UK government announced eight freeports where businesses can import goods without paying tariffs, unless those goods are sold in the wider UK market."}'::jsonb, '{"answer": true, "explain": "TRUE. Freeports allow businesses to import goods tariff-free and VAT-free. Duties are only paid if the goods enter the wider UK market. If the goods are exported after processing, no duties are paid at all — encouraging trade and investment."}'::jsonb),
('4-5-business-location:learn:097cf97a', '4-5-business-location', '4.5 Business Location', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>Understanding the key vocabulary for business location is essential for exam success.</p>\n<ul>\n  <li><strong>Location:</strong> The place where a business is sited.</li>\n  <li><strong>Proximity:</strong> Means ''nearness to'' — e.g., proximity to the market means being close to customers.</li>\n  <li><strong>Transport infrastructure:</strong> The provision of roads, railways, ports and airports in an area for transporting goods and people, including ICT infrastructure such as broadband.</li>\n  <li><strong>Labour:</strong> A factor of production — the workers employed by businesses to produce goods and services.</li>\n  <li><strong>Raw materials:</strong> Materials that are processed in some way as part of the manufacture of a product.</li>\n  <li><strong>Enterprise zone:</strong> A government-designated area where businesses are offered incentives such as reduced business rates, lower taxes on investment, and superfast broadband to encourage them to locate there.</li>\n  <li><strong>Freeport:</strong> An area where businesses can import goods without paying tariffs or VAT — duties are only payable if goods are sold in the wider UK market.</li>\n  <li><strong>Northern Powerhouse:</strong> A UK Government initiative to encourage businesses to locate, stay and expand in the north of England by improving infrastructure and providing funding from Liverpool to Hull.</li>\n</ul>", "question": "What is the key difference between an Enterprise Zone and a Freeport?", "options": ["They are identical — both offer the exact same package of incentives to businesses", "Enterprise zones cut business rates and taxes; freeports also let firms import goods tariff-free", "Freeports are only open to food and farming businesses, unlike enterprise zones", "Enterprise zones let firms import goods tariff-free, while freeports only cut business rates"]}'::jsonb, '{"answer": 1, "explain": "Enterprise zones offer incentives like reduced business rates, lower taxes on investment, and superfast broadband. Freeports go further — goods can be imported without paying tariffs or VAT until they enter the wider UK market, making them especially attractive for businesses that import, process and re-export."}'::jsonb),
('4-5-business-location:learn:98db3549', '4-5-business-location', '4.5 Business Location', 'learn', 'mcq', 1, '{"readingTitle": "Why Location Matters", "reading": "<p>For many businesses, choosing <strong>where to locate</strong> is one of the most critical decisions they make. The right location can help a business flourish; the wrong one can make success almost impossible.</p>\n<p>Location affects a business across multiple areas:</p>\n<ul>\n  <li>The <strong>costs</strong> of running the business (rent, wages, transport)</li>\n  <li>Access to <strong>customers</strong> and sales potential</li>\n  <li>Access to <strong>skilled workers</strong></li>\n  <li>Access to <strong>raw materials</strong> and suppliers</li>\n</ul>\n<p>It is rarely just <strong>one</strong> factor that determines where a business locates — usually it is a <strong>combination of factors</strong>. As globalisation increases, some businesses (especially multinationals) consider locations in different countries, not just different regions.</p>\n<div class=\"case-study-box\">\n  <h4>Key Evaluation Point</h4>\n  <p>Proximity to the market remains a very important factor for many businesses. However, the growth of internet selling and the reduction in transport and shipping costs has made it possible for more and more businesses to compete even when not near their customers. A business like <strong>Amazon</strong> competes effectively by selling vast quantities at low prices from strategically positioned warehouses — proximity to the customer is far less important than proximity to a good road network.</p>\n</div>", "question": "Why is Amazon''s location strategy different from that of a traditional retailer?", "options": ["Amazon ignores location completely, since online sales make the site irrelevant", "Amazon values good road links over closeness to customers, selling from warehouses", "Amazon needs to sit right next to its customers, just like a high street shop", "Amazon''s warehouse sites are chosen purely by where its raw material suppliers sit"]}'::jsonb, '{"answer": 1, "explain": "Amazon sells online at high volumes, so being near a motorway network for fast delivery matters far more than being near any individual customer — unlike a high street retailer which relies on footfall."}'::jsonb),
('4-5-business-location:learn:abaf56fd', '4-5-business-location', '4.5 Business Location', 'learn', 'mcq', 1, '{"readingTitle": "Factor 1: Costs", "reading": "<p>The <strong>cost of production</strong> varies significantly between locations. Businesses look for sites where costs are kept as low as possible without sacrificing access to key resources.</p>\n<ul>\n  <li><strong>Site and premises costs:</strong> Rents in prosperous cities like London and Cambridge are far higher than in areas with declining industries like Teesside. The cost of the location must be recovered through the prices charged — higher costs can reduce competitiveness.</li>\n  <li><strong>Labour costs:</strong> Wages vary by region. In 2021, the average salary in London was £38,000 vs £33,000 in Leeds — a significant saving for employers considering a move north.</li>\n  <li><strong>Transport costs:</strong> Good road, rail, sea and air links reduce the cost of moving raw materials and finished goods.</li>\n  <li><strong>ICT infrastructure:</strong> Fast broadband and reliable digital communications are increasingly essential for modern businesses.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Cambridge Research Biochemicals (CRB)</h4>\n  <p>CRB produces peptides and antibodies. Originally based in Cambridge, it moved to Billingham in Teesside in 1999 because rents there were only <strong>10% of those in Cambridge</strong>. Labour was also cheaper. In 2014, CRB used a government ''Let''s Grow'' grant of £65,000 to move to the Teesside Valley enterprise zone — receiving both cost savings and government support.</p>\n  <p><strong>Takeaway:</strong> Production cost savings can be so significant that businesses relocate over long distances. Government incentives can make the decision even more attractive.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Burberry</h4>\n  <p>Burberry — a luxury fashion brand with a Royal Warrant — moved production from Wales to China because UK factory and labour costs were higher than almost anywhere else in the world.</p>\n  <p><strong>Takeaway:</strong> Even prestigious brands prioritise cost efficiency, especially when manufacturing is labour-intensive.</p>\n</div>", "question": "Cambridge Research Biochemicals moved to Teesside in 1999. What was the key financial reason?", "options": ["Teesside offered much faster transport links into central London than Cambridge did", "Rents in Teesside were only 10% of Cambridge rents, saving huge sums", "Government regulations legally required all biochemical firms to relocate to Teesside", "Cambridge had completely lost its supply of skilled biochemical research workers"]}'::jsonb, '{"answer": 1, "explain": "CRB relocated because rents in Teesside were only 10% of Cambridge rents — a 90% reduction in premises costs. This was further enhanced in 2014 by a £65,000 government ''Let''s Grow'' grant when they moved into the Teesside Valley enterprise zone."}'::jsonb),
('4-5-business-location:learn:decd9f61', '4-5-business-location', '4.5 Business Location', 'learn', 'mcq', 1, '{"readingTitle": "Factor 2: Proximity to the Market", "reading": "<p><strong>Proximity to the market</strong> means locating close to the business''s customers. This is especially important for service businesses and retailers.</p>\n<ul>\n  <li><strong>Service businesses</strong> (e.g., hairdressers, dentists, cafés) must locate near consumers, who are unlikely to travel far.</li>\n  <li><strong>Retailers</strong> consider the number of potential customers, the level of competition, and whether the local population will buy the product.</li>\n  <li><strong>Manufacturers</strong> may locate near buyers for easy communication and to reduce delivery costs — e.g., Toyota Tsusho UK makes wheels for Jaguar Land Rover cars and is sited just 33 miles from JLR''s Castle Bromwich assembly plant.</li>\n  <li><strong>Online businesses</strong> have changed this dynamic — they need good transport links for their warehouses rather than a high-street location.</li>\n</ul>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Benefits of Locating Near the Market</div>\n    <div class=\"pro-item\"><strong>Higher footfall:</strong> More passing customers means greater potential sales revenue for retailers and service businesses.</div>\n    <div class=\"pro-item\"><strong>Lower delivery costs:</strong> Shorter distances to customers reduce transport expenses for manufacturers.</div>\n    <div class=\"pro-item\"><strong>Better communication:</strong> Easier to respond quickly to customer needs, complaints and orders.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Drawbacks of Locating Near the Market</div>\n    <div class=\"con-item\"><strong>Higher rents:</strong> Prime locations (town centres, airports) command much higher rental costs, increasing overheads.</div>\n    <div class=\"con-item\"><strong>More competition:</strong> Popular locations attract rival businesses, increasing competitive pressure and potentially driving down prices.</div>\n    <div class=\"con-item\"><strong>Not always necessary:</strong> Online businesses and manufacturers of small, lightweight goods do not always need to be near their customers.</div>\n  </div>\n</div>", "question": "Toyota Tsusho UK makes wheels for Jaguar Land Rover and is located just 33 miles from JLR''s Castle Bromwich plant. Which location factor does this best illustrate?", "options": ["Proximity to raw materials — Toyota Tsusho needs steel supplies close by", "Proximity to market — Toyota Tsusho sits near JLR to cut delivery costs", "Government incentives — the West Midlands site sits inside an enterprise zone", "Labour availability — Castle Bromwich has a large pool of skilled engineers"]}'::jsonb, '{"answer": 1, "explain": "Toyota Tsusho UK is a manufacturer whose main customer is JLR. Locating 33 miles away reduces delivery costs for bulky car wheels and makes it easier to respond quickly to JLR''s production schedule — a classic example of a manufacturer locating near its market."}'::jsonb),
('4-5-business-location:learn:280aee35', '4-5-business-location', '4.5 Business Location', 'learn', 'mcq', 1, '{"readingTitle": "Factor 3: Proximity to Raw Materials", "reading": "<p>Some businesses — particularly <strong>manufacturers</strong> — need to locate close to their raw material sources. This is most important when:</p>\n<ul>\n  <li>Raw materials are <strong>bulky</strong> and costly to transport (e.g., wheat, iron ore, stone).</li>\n  <li>Raw materials are <strong>perishable</strong> (e.g., fresh milk for cheese-making).</li>\n  <li>The finished product is <strong>smaller and lighter</strong> than the raw material, making it more efficient to process on-site before transporting.</li>\n</ul>\n<p>There is also an <strong>environmental benefit</strong>: shorter supply chains reduce carbon emissions and help businesses present themselves as environmentally responsible.</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: Cargill Foods, Liverpool Docks</h4>\n  <p>Cargill Foods processes wheat imported from several countries. Its factory is located directly on the Liverpool docks — wheat arriving by ship is unloaded straight into the factory. If the factory were elsewhere, the wheat would need to be loaded onto lorries, transported, and unloaded again, adding significant cost and time.</p>\n  <p><strong>Takeaway:</strong> When raw materials arrive by sea, locating at a port can dramatically cut transport costs and improve operational efficiency.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Dewlay Cheesemakers, Lancashire</h4>\n  <p>Dewlay buys milk from dairy farms within six miles of its dairy in Garstang, Lancashire. This reduces transport costs <em>and</em> allows Dewlay to market its ''green'' credentials — it was the first cheese producer to generate its own electricity from a wind turbine.</p>\n  <p><strong>Takeaway:</strong> Locating near raw materials can bring both financial savings and reputational benefits in an environmentally conscious market.</p>\n</div>", "question": "Why does Cargill Foods locate its factory directly on the Liverpool docks rather than inland?", "options": ["Liverpool offers the lowest labour costs of any UK port city", "Wheat is unloaded from ships straight into the factory, cutting cost", "Government regulations require all food processors to sit at ports", "Liverpool docks charge the cheapest factory rent of any UK location"]}'::jsonb, '{"answer": 1, "explain": "Cargill imports wheat by sea — locating at the docks means the wheat goes straight from ship to factory with no intermediate transport. Moving the factory inland would add lorry transport, extra loading/unloading, and significant cost."}'::jsonb),
('4-5-business-location:learn:d2a48703', '4-5-business-location', '4.5 Business Location', 'learn', 'mcq', 1, '{"readingTitle": "Factor 4: Proximity to Labour", "reading": "<p>All businesses need workers. The availability and cost of <strong>labour</strong> in an area is a key location factor, especially when a business requires large numbers of workers or specific skills.</p>\n<ul>\n  <li>Businesses needing <strong>skilled workers</strong> may locate near universities or in established industry clusters. <strong>''Silicon Fen''</strong> near Cambridge is a concentration of ICT firms and skilled technology workers.</li>\n  <li>Businesses needing large numbers of <strong>unskilled or semi-skilled</strong> workers may target areas of high population or high unemployment, where labour is plentiful and wages may be lower.</li>\n  <li>In areas where traditional industries (coal mining, steel, shipbuilding) have declined, labour supply is often <strong>plentiful and relatively cheap</strong>.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Channel 4 Moves to Leeds</h4>\n  <p>Channel 4 opened additional headquarters in Leeds. Key reasons: office space costs £250–£300/month in Leeds vs £650–£2,500/month in London; average salaries are lower (£33,000 vs £38,000); and Leeds has three universities — three-quarters of Leeds Beckett graduates stay in the city, providing a strong talent pipeline.</p>\n  <p><strong>Takeaway:</strong> For office-based businesses, northern cities can offer a compelling mix of lower costs AND a well-educated, skilled labour pool.</p>\n</div>", "question": "What specific labour advantage did Leeds offer Channel 4 compared to London?", "options": ["Leeds has more television and media production studios", "Lower salaries plus strong graduate retention from universities", "Employment law requires Leeds staff to work longer hours", "The government pays Channel 4 staff salaries directly in Leeds"]}'::jsonb, '{"answer": 1, "explain": "Leeds offered Channel 4 both lower salaries (£33,000 vs £38,000 in London) and a ready supply of graduates — three-quarters of Leeds Beckett graduates stay in the city — making it both cheaper and talent-rich compared to London."}'::jsonb),
('4-5-business-location:learn:ed965862', '4-5-business-location', '4.5 Business Location', 'learn', 'mcq', 1, '{"readingTitle": "Factor 5: Government Influence", "reading": "<p>Governments — national and local — often try to <strong>influence where businesses locate</strong> to create jobs and raise incomes in specific regions.</p>\n<ul>\n  <li><strong>Enterprise Zones (48 in the UK):</strong> Businesses benefit from reduced business rates, higher capital allowances (lower taxes on investment), superfast broadband, faster planning approvals, and ready-built premises. Four enterprise zones are in South Wales.</li>\n  <li><strong>Freeports (8 announced in 2021):</strong> Businesses can import goods without paying tariffs or VAT. If goods are exported after processing, no duties are paid at all — encouraging trade, investment and job creation.</li>\n  <li><strong>The Northern Powerhouse:</strong> Invests in infrastructure and provides funds for businesses starting or growing in northern England, from Liverpool to Hull.</li>\n  <li><strong>Regional Growth Funds:</strong> One-off government grants to help businesses relocate or expand in high-unemployment areas (e.g., CRB''s £65,000 ''Let''s Grow'' grant).</li>\n</ul>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Benefits of Government Incentives</div>\n    <div class=\"pro-item\"><strong>Reduced costs:</strong> Lower business rates and taxes directly improve profitability for businesses locating in enterprise zones.</div>\n    <div class=\"pro-item\"><strong>Grant funding:</strong> One-off financial support reduces start-up or relocation costs significantly.</div>\n    <div class=\"pro-item\"><strong>Infrastructure improvements:</strong> Government investment in roads, broadband, and buildings makes areas more attractive over time.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Limitations of Government Incentives</div>\n    <div class=\"con-item\"><strong>Temporary benefits:</strong> Incentives may not last forever — once they end, the underlying disadvantages of the location remain.</div>\n    <div class=\"con-item\"><strong>Other factors persist:</strong> Incentives alone cannot compensate for poor transport links, low skilled labour supply, or limited customer base.</div>\n    <div class=\"con-item\"><strong>Bureaucracy:</strong> Applying for grants or enterprise zone status can be time-consuming and the outcome is uncertain.</div>\n  </div>\n</div>", "question": "How many Enterprise Zones and Freeports were there in the UK at the time covered in this topic?", "options": ["8 Enterprise Zones and 48 Freeports", "48 Enterprise Zones and 8 Freeports", "4 Enterprise Zones and 4 Freeports", "100 Enterprise Zones and 20 Freeports"]}'::jsonb, '{"answer": 1, "explain": "There are 48 Enterprise Zones (including four in South Wales) and 8 Freeports announced in 2021. The numbers are easy to mix up — remember there are far more enterprise zones than freeports."}'::jsonb),
('4-5-business-location:learn:1a1461b9', '4-5-business-location', '4.5 Business Location', 'learn', 'mcq', 1, '{"readingTitle": "Online vs Physical Location", "reading": "<p>The rise of <strong>e-commerce</strong> has fundamentally changed location decisions. Online businesses have very different priorities to traditional high-street retailers.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of an Online/Warehouse Location</div>\n    <div class=\"pro-item\"><strong>Lower costs:</strong> Warehouses on the outskirts or in industrial areas have far lower rents than high-street shops, improving profit margins.</div>\n    <div class=\"pro-item\"><strong>Wider market reach:</strong> An online business is not restricted to local customers — it can sell nationally or globally from a single location.</div>\n    <div class=\"pro-item\"><strong>Location flexibility:</strong> The business can locate wherever land, labour, and transport links are most cost-effective.</div>\n    <div class=\"pro-item\"><strong>Scalability:</strong> Easier to expand warehouse space than to open multiple physical shops.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of an Online/Warehouse Location</div>\n    <div class=\"con-item\"><strong>No walk-in customers:</strong> Cannot benefit from passing trade or impulse purchases — all marketing must drive customers to the website.</div>\n    <div class=\"con-item\"><strong>Transport dependency:</strong> Must have excellent road/rail links and reliable delivery partners to reach customers on time.</div>\n    <div class=\"con-item\"><strong>Brand visibility:</strong> Without a physical presence, building brand recognition is harder and more expensive.</div>\n    <div class=\"con-item\"><strong>Returns logistics:</strong> Managing customer returns across a wide geographic area can be costly and complex.</div>\n  </div>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: The Wool Warehouse</h4>\n  <p>Set up in 2012, the Wool Warehouse deliberately chose a warehouse rather than a high street shop to enter the online yarn market. At the time, there were only 2–3 yarn suppliers online. Online sales took off, and by 2014 they doubled their warehouse space as their range expanded.</p>\n  <p><strong>Takeaway:</strong> Going online allowed the Wool Warehouse to enter a market with very little competition, reach customers nationally, and keep overheads low — all without needing a prime retail location.</p>\n</div>", "question": "When The Wool Warehouse launched in 2012, what market condition made the online strategy particularly attractive?", "options": ["There were hundreds of yarn competitors already selling online by that point", "There were only 2–3 yarn suppliers online, meaning almost no competition", "The government awarded them a large grant specifically to launch online sales", "Every high street yarn shop in the country had already shut down by 2012"]}'::jsonb, '{"answer": 1, "explain": "In 2012 there were only 2–3 online yarn suppliers — almost no competition. The Wool Warehouse seized that gap, reaching customers nationally without the cost of a high-street location. By 2014 they doubled their warehouse space as sales grew."}'::jsonb),
('4-5-business-location:misc:4cba40a2', '4-5-business-location', '4.5 Business Location', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think ''the high street'' is the only location option for a business.</p><p><strong>✅ The correct idea:</strong> Businesses can locate anywhere — high streets, industrial estates, online warehouses, near ports, in enterprise zones. The best location depends entirely on the type of business and which factors are most important to it.</p>", "question": "Which of the following is NOT a valid location option for a business?", "options": ["An out-of-town industrial estate", "A warehouse near a motorway junction", "A government enterprise zone", "All of these are valid location options"]}'::jsonb, '{"answer": 3, "explain": "All of these — industrial estates, motorway-adjacent warehouses, and enterprise zones — are perfectly valid location options. There is no single ''right'' location type; it depends entirely on the business''s needs."}'::jsonb),
('4-5-business-location:misc:7c00b084', '4-5-business-location', '4.5 Business Location', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse ''proximity to market'' (near customers) with ''proximity to raw materials'' (near suppliers).</p><p><strong>✅ The correct idea:</strong> These are two completely separate location factors. ''Proximity to market'' = near customers. ''Proximity to raw materials'' = near suppliers of inputs. A business can prioritise one, the other, or both — depending on what it produces.</p>", "question": "Dewlay Cheesemakers sources milk from farms within six miles of its dairy. Which location factor is this?", "options": ["Proximity to market — Dewlay is close to its cheese buyers", "Proximity to raw materials — Dewlay is close to milk suppliers", "Government incentives — the farms are in an enterprise zone", "Labour availability — farm workers make the cheese"]}'::jsonb, '{"answer": 1, "explain": "Milk is the raw material for cheese-making. Dewlay locates near its dairy farms (suppliers of milk) to minimise transport costs and keep milk fresh — this is proximity to raw materials, not proximity to market."}'::jsonb)
